import React, { useState } from 'react';
import Button from '@mui/material/Button';
import Grid from '@mui/material/Grid';
import Typography from '@mui/material/Typography';
import MenuItem from '@mui/material/MenuItem';
import Select from '@mui/material/Select';
import InputLabel from '@mui/material/InputLabel';
import FormControl from '@mui/material/FormControl';

const INITIAL_STATE = Array(9).fill(null);

const calculateWinner = (squares) => {
  const lines = [
    [0, 1, 2],
    [3, 4, 5],
    [6, 7, 8],
    [0, 3, 6],
    [1, 4, 7],
    [2, 5, 8],
    [0, 4, 8],
    [2, 4, 6],
  ];
  for (let i = 0; i < lines.length; i++) {
    const [a, b, c] = lines[i];
    if (squares[a] && squares[a].player === squares[b].player && squares[a].player === squares[c].player) {
      return squares[a].player;
    }
  }
  return null;
};

const TicTacToe = () => {
  const [board, setBoard] = useState(INITIAL_STATE);
  const [xIsNext, setXIsNext] = useState(true);
  const [selectedSize, setSelectedSize] = useState(3);

  const handleClick = (index) => {
    if (board[index] || calculateWinner(board)) {
      return;
    }

    const newBoard = board.slice();
    newBoard[index] = { player: xIsNext ? 'X' : 'O', size: selectedSize };
    setBoard(newBoard);
    setXIsNext(!xIsNext);
  };

  const handleSizeChange = (event) => {
    setSelectedSize(event.target.value);
  };

  const renderSquare = (index, size) => (
    <Button
      variant="outlined"
      size="large"
      style={{ width: `${size * 30}px`, height: `${size * 30}px`, fontSize: `${size * 1.5}rem` }}
      onClick={() => handleClick(index)}
    >
      {board[index] && board[index].player}
    </Button>
  );

  const winner = calculateWinner(board);
  const status = winner ? `Winner: ${winner}` : `Next player: ${xIsNext ? 'X' : 'O'}`;

  return (
    <div style={{ textAlign: 'center', marginTop: '20px' }}>
      <Typography variant="h4" gutterBottom>
        Tic Tac Toe
      </Typography>
      <Typography variant="h6" gutterBottom>
        {status}
      </Typography>
      <Grid container spacing={1}>
        {[0, 1, 2].map((row) => (
          <Grid container item key={row} justifyContent="center">
            {[0, 1, 2].map((col) => (
              <Grid item key={col}>
                {renderSquare(row * 3 + col, board[row * 3 + col] ? board[row * 3 + col].size : 1)}
              </Grid>
            ))}
          </Grid>
        ))}
      </Grid>
      <FormControl variant="outlined" style={{ marginTop: '20px' }}>
        <InputLabel id="size-selector-label">Select Size</InputLabel>
        <Select
          labelId="size-selector-label"
          id="size-selector"
          value={selectedSize}
          onChange={handleSizeChange}
          label="Select Size"
        >
          <MenuItem value={1}>Small</MenuItem>
          <MenuItem value={2}>Medium</MenuItem>
          <MenuItem value={3}>Large</MenuItem>
        </Select>
      </FormControl>
    </div>
  );
};

export default TicTacToe;
